export function getIntentCategory(rawIntentId: string): string {
  const id = rawIntentId.split(" - ")[0].trim()
  return INTENT_CATEGORY_MAP[id] ?? "Others"
}

export function getIntentName(rawIntentId: string): string {
  const id = rawIntentId.split(" - ")[0].trim()
  return INTENT_NAME_MAP[id] ?? rawIntentId
}

export function getIntentId(rawIntentId: string): string {
  return rawIntentId.split(" - ")[0].trim()
}